@ProcessorAnnotation(key = "S1596", description = "\"Collections.EMPTY_LIST\", \"EMPTY_MAP\", and \"EMPTY_SET\" should not be used")
public class CollectionsEmptyConstantsProcessor extends SoraldAbstractProcessor<CtFieldAccess<?>> {
    @Override
    protected void repairInternal(CtFieldAccess<?> element) {
        String[] loweredNameParts = element.getVariable().getSimpleName().toLowerCase().split("_");
        String camelCasedName = loweredNameParts[0] + capitalize(loweredNameParts[1]);
        CtMethod<?> methodToBeCalled = getFactory().Class().get(Collections.class).getMethod(camelCasedName);
        CtInvocation<?> newInvocation = getFactory().createInvocation(element.getTarget(), methodToBeCalled.getReference());
        element.replace(newInvocation);
    }
}

package sorald.processor;
import spoon.reflect.code.CtComment;
import spoon.reflect.code.CtConstructorCall;
import var;
import sorald.annotations.ProcessorAnnotation;
@ProcessorAnnotation(key = "S3984", description = "Exception should not be created without being thrown")
public class UnusedThrowableProcessor extends SoraldAbstractProcessor<CtConstructorCall<? extends Throwable>> {
    @Override
    protected void repairInternal(CtConstructorCall<? extends Throwable> element) {
        var ctThrow = getFactory().createThrow();
        var thrownExpr = element.clone();
        for (CtComment comment : thrownExpr.getComments()) {
            comment.delete();
            ctThrow.addComment(comment);
        }
        ctThrow.setThrownExpression(thrownExpr);
        element.replace(ctThrow);
    }
}

